import{_ as l,c as i,o as s,ae as o,j as a,t as r}from"./chunks/framework.B7Y1jjX-.js";const g=JSON.parse('{"title":"Vue的双向绑定的原理","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/框架/Vue/Vue的双向绑定的原理.md","filePath":"notes/前端/框架/Vue/Vue的双向绑定的原理.md"}'),n={name:"notes/前端/框架/Vue/Vue的双向绑定的原理.md"};function d(t,e,c,u,p,h){return s(),i("div",null,[e[0]||(e[0]=o('<h1 id="vue的双向绑定的原理" tabindex="-1">Vue的双向绑定的原理 <a class="header-anchor" href="#vue的双向绑定的原理" aria-label="Permalink to &quot;Vue的双向绑定的原理&quot;">​</a></h1><h2 id="vue底层实现原理" tabindex="-1">Vue底层实现原理 <a class="header-anchor" href="#vue底层实现原理" aria-label="Permalink to &quot;Vue底层实现原理&quot;">​</a></h2><ul><li>vue是采用<strong>数据劫持</strong>+<strong>发布者-订阅者模式</strong>的方式 <ul><li>通过<code>Object.defineProperty()</code>来劫持各个属性的getter和setter；</li><li>在数据变动时，触发set，在set中调用<code>dep.notify()</code>方法,发布消息给<strong>订阅者</strong>（订阅者就是Watcher，依赖收集器dep中的subs），做出对应的回调函数，更新视图</li></ul></li></ul><h2 id="_1-原理概述" tabindex="-1">1. 原理概述 <a class="header-anchor" href="#_1-原理概述" aria-label="Permalink to &quot;1. 原理概述&quot;">​</a></h2><blockquote><p>vue中每个data数据都有一个dep，当获取数据时会在get方法中添加一个新的订阅者，并将订阅者存放到发布者中。当数据发生改变的时候在set方法中调用<code>dep.notice</code>方法，让dep中所有的订阅者执行update函数</p></blockquote><ul><li>以<strong>数据劫持</strong> + <strong>发布者-订阅者</strong>模式实现，</li><li>首先通过<code>Object.defineproperty()</code>来劫持各属性的<code>getter</code>和<code>setter</code>，</li><li>当获取某个属性值时，会触发该属性的 getter，发布者就可以将该属性加入<strong>订阅者的集合管理数组dep</strong>中，</li><li>当更新某个属性值时，就会触发该属性的setter，发布者可以调用dep.notice()方法，通知订阅者调用<strong>自身的 update()</strong> 方法进行更新，</li></ul><h3 id="_1-简化版" tabindex="-1">（1）简化版： <a class="header-anchor" href="#_1-简化版" aria-label="Permalink to &quot;（1）简化版：&quot;">​</a></h3><ul><li>Vue2.x <ul><li>简单来说，就是<strong>数据劫持</strong> + <strong>发布者-订阅者</strong>模式实现，通过<code>object.defineproperty()</code>来劫持各属性的<code>getter</code>和<code>setter</code>，在数据变更时通知订阅者，触发相应的监听回调，实现视图更新。</li></ul></li><li>Vue3.0 <ul><li>vue.js 是采用数据劫持结合发布者-订阅者模式的方式，通过<code>new Proxy()</code>来劫持各个属性的setter，getter，在数据变动时发布消息给订阅者，触发相应的监听回调</li></ul></li></ul><p>2与3都是数据劫持+发布者+订阅者的结构，不过底层实现的原理发生了变化</p><h3 id="_2-详细版" tabindex="-1">（2）详细版： <a class="header-anchor" href="#_2-详细版" aria-label="Permalink to &quot;（2）详细版：&quot;">​</a></h3><p>将mvvm作为数据绑定的入口，整合observer、compile、watcher</p><ul><li>对每个vue属性使用<code>objecet.defineproperty()</code>来劫持各属性的getter和setter，每个属性分配一个<strong>订阅者集合管理数组dep</strong></li><li>订阅者来自compile，一旦数据改变，通知watcher绑定更新函数，同时<strong>向dep添加订阅者</strong></li><li>当dep接到observer变化时，会通知watcher，watcher调用<strong>update()方法</strong>，触发compile绑定的<strong>回调</strong>，视图更新。</li></ul><h3 id="_3-具体版" tabindex="-1">（3）具体版： <a class="header-anchor" href="#_3-具体版" aria-label="Permalink to &quot;（3）具体版：&quot;">​</a></h3><ul><li>（1）需要 observe 的数据对象进行<strong>递归遍历</strong>，包括子属性对象的属性，都加上 setter 和 getter , 这样的话，给这个对象的某个值赋值，就会触发 setter，那么就能监听到数据变化 <ul><li>Observer的核心是通过<code>Object.defineProprtty()</code>来监听数据的变动，这个函数内部可以定义<code>setter和getter</code>;</li><li>每当数据发生变化，就会触发setter。这时候Observer就要通知订阅者，订阅者就是Watcher</li></ul></li><li>（2）Compile（指令解析器）主要做的事情是解析模板指令 <ul><li><strong>将模板中变量替换成数据</strong>，然后初始化<strong>渲染页面视图</strong></li><li>并将每个指令对应的节点<strong>绑定更新函数</strong>，添加监听数据的订阅者，<strong>一旦数据有变动，收到通知，更新试图</strong></li></ul></li><li>（3）Watcher 订阅者是 Observer 和 Compile 之间通信的桥梁，主要做的事情是: <ul><li>在自身实例化时往<code>属性订阅器(dep)</code>里面添加自己</li><li>自身必须有一个<code>update()</code>方法</li><li>待属性变动调用<code>dep.notice()</code>通知时，能**调用自身的<code>update()</code>方法，并触发<code>Compile</code>中绑定的回调</li></ul></li><li>MVVM作为绑定的入口，整合Observer,Compile和Watcher三者， <ul><li>Observer 来监听自己的 model 数据变化</li><li>通过 Compile 来解析编译模板指令</li><li>最终利用 Watcher 搭起 Observer 和 Compile 之间的通信桥梁</li><li>达到<strong>数据变化Observer=&gt;视图更新</strong>；<strong>视图交互变化=&gt;数据model变更</strong>的双向绑定效果。 <img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/f2e45bb687764d32b1a51af53486b911~tplv-k3u1fbpfcp-jj-mark:3024:0:0:0:q75.awebp#?w=851&amp;h=81&amp;s=10734&amp;e=png&amp;a=1&amp;b=fdfcfc" alt="image.png"></li></ul></li></ul><h2 id="_2-数据劫持" tabindex="-1">2. 数据劫持 <a class="header-anchor" href="#_2-数据劫持" aria-label="Permalink to &quot;2. 数据劫持&quot;">​</a></h2><p>检测data变化的核心API：<code>Object.defindeProperty</code></p><p><code>const dep = new Dep(); // 依赖收集器 // 劫持并监听所有属性 Object.defineProperty(obj, key, { enumerable: true, configurable: false, get() { console.log(&#39;触发get&#39;); // 订阅数据变化时，在Dep中添加订阅者 Dep.target &amp;&amp; dep.addSub(Dep.target); //用到这个数据的时候就添加监听 return value; }, set: newVal =&gt; { console.log(&#39;触发set&#39;); if (newVal !== value) { this.observe(newVal); value = newVal; } // 告诉Dep通知变化，通知视图更新... dep.notify(); } }); //测试 const data = {}; let name = &#39;张三&#39;; console.log(data.name); // 获取数据的时候会触发get 张三 data.name = &#39;李四&#39;; // 赋值的时候会触发set</code></p><p>这样就是可以实现数据的获取和赋值的监听</p><h2 id="_3-发布者-订阅者模式⭐⭐⭐⭐⭐" tabindex="-1">3. 发布者-订阅者模式⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_3-发布者-订阅者模式⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;3. 发布者-订阅者模式⭐⭐⭐⭐⭐&quot;">​</a></h2><ul><li>data中每一个数据都绑定一个Dep，这个Dep中都存有所有用到该数据的<strong>订阅者</strong></li><li>当数据改变时，发布消息给dep（依赖收集器），去通知每一个订阅者，做出对应的回调函数</li></ul>',20)),a("p",null,[a("code",null,'// 订阅者 class Watcher { // name模拟使用属性的地方 constructor(name, cb) { this.name = name this.cb = cb } update() {//更新 console.log(this.name + "更新了"); this.cb() //做出更新回调 } } // 发布者（依赖收集器） class Dep { constructor() { this.subs = [] //订阅者 } // 添加订阅者 addSubs(watcher) { this.subs.push(watcher) } // 当有数据更新时，通知每一个订阅者做出更新 notify() { this.subs.forEach(w => { w.update()//每个订阅者Watcher自身有一个update()方法 }); } } // 假如现在用到age的有三个地方 let w1 = new Watcher("我'+r(t.age)+'了", () => { console.log("更新age"); }) let w2 = new Watcher("v-model:age", () => { console.log("更新age"); }) let w3 = new Watcher("I am '+r(t.age)+' years old", () => { console.log("更新age"); }) //添加订阅者 let dep = new Dep() dep.addSubs(w1) dep.addSubs(w2) dep.addSubs(w3) // 在Object.defineProperty 中的 set中运行 ☆ dep.notify()',1)]),e[1]||(e[1]=o('<h2 id="延伸问题" tabindex="-1">[ 延伸问题 ] <a class="header-anchor" href="#延伸问题" aria-label="Permalink to &quot;[ 延伸问题 ]&quot;">​</a></h2><h3 id="_1-vue是如何监听数组的-⭐⭐⭐⭐⭐" tabindex="-1">(1) <a href="https://link.juejin.cn/?target=https%3A%2F%2Fwenku.baidu.com%2Fview%2F3feb2167bd1e650e52ea551810a6f524cdbfcb41.html" title="https://wenku.baidu.com/view/3feb2167bd1e650e52ea551810a6f524cdbfcb41.html" target="_blank" rel="noreferrer">Vue是如何监听数组的？</a>⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_1-vue是如何监听数组的-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;(1) [Vue是如何监听数组的？](https://link.juejin.cn/?target=https%3A%2F%2Fwenku.baidu.com%2Fview%2F3feb2167bd1e650e52ea551810a6f524cdbfcb41.html &quot;https://wenku.baidu.com/view/3feb2167bd1e650e52ea551810a6f524cdbfcb41.html&quot;)⭐⭐⭐⭐⭐&quot;">​</a></h3><ul><li>首先第一点是要看数组里面是不是还存在对象，如果存在对象的话再进行深层遍历看是否还依然存在对象，再把对象进行 <code>defineProperty监听</code>。</li><li>在将数组处理成响应式数据后，如果使用数组原始方法改变数组时，数组值会发生变化，但是并不会触发数组的setter来通知所有依赖该数组的地方进行更新，</li><li>为此，vue通过<strong>重写</strong>数组的<code>push、pop、shift、unshift、splice、sort、reverse</code>七种方法来监听数组变化，重写后的方法中会手动触发通知该数组的所有依赖进行更新。</li></ul>',3))])}const m=l(n,[["render",d]]);export{g as __pageData,m as default};
